namespace BgControls.Windows.DragDrop;/// <summary>/// 拖拽操作辅助类，管理拖拽视觉效果和交互逻辑./// </summary>internal class DragHelper{    /// <summary>    /// UI 元素装饰器，用于在装饰层展示自定义 UI 元素.    /// </summary>    internal class UIElementAdorner : Adorner    {        private double leftOffset;        private double topOffset;        private UIElement child;        /// <summary>        /// Initializes a new instance of the <see cref="UIElementAdorner"/> class.        /// </summary>        /// <param name="uiElement">要显示的子元素.</param>        /// <param name="owner">装饰的目标元素.</param>        public UIElementAdorner(UIElement uiElement, UIElement owner)            : base(owner)        {            this.child = uiElement;            // 将子元素添加到视觉树.            this.AddVisualChild(this.child);        }        /// <summary>        /// Gets or sets 左侧偏移量.        /// </summary>        public double LeftOffset        {            get            {                return this.leftOffset;            }            set            {                this.leftOffset = value;                this.UpdatePosition();            }        }        /// <summary>        /// Gets or sets 顶部偏移量.        /// </summary>        public double TopOffset        {            get            {                return this.topOffset;            }            set            {                this.topOffset = value;                this.UpdatePosition();            }        }        /// <summary>        /// Gets 正在修饰的视觉元素.        /// </summary>        protected UIElement AdornVisual => this.child;        /// <summary>        /// Gets 视觉子元素的数量.        /// </summary>        protected override int VisualChildrenCount => 1;        /// <summary>        /// 获取指定索引处的视觉子元素.        /// </summary>        /// <param name="index">索引值.</param>        /// <returns>视觉子元素.</returns>        protected override Visual GetVisualChild(int index)        {            return this.child;        }        /// <summary>        /// 测量子元素的大小.        /// </summary>        /// <param name="finalSize">约束大小.</param>        /// <returns>期望的大小.</returns>        protected override Size MeasureOverride(Size finalSize)        {            this.child.Measure(finalSize);            return this.child.DesiredSize;        }        /// <summary>        /// 安排子元素的位置.        /// </summary>        /// <param name="finalSize">最终大小.</param>        /// <returns>实际使用的大小.</returns>        protected override Size ArrangeOverride(Size finalSize)        {            this.child.Arrange(new Rect(this.child.DesiredSize));            return finalSize;        }        /// <summary>        /// 获取装饰器期望的变换矩阵，用于处理偏移.        /// </summary>        /// <param name="transform">原始变换.</param>        /// <returns>组合后的变换.</returns>        public override GeneralTransform GetDesiredTransform(GeneralTransform transform)        {            GeneralTransformGroup transformGroup = new GeneralTransformGroup();            // 添加基类的变换.            transformGroup.Children.Add(base.GetDesiredTransform(transform));            // 添加平移变换处理偏移量.            transformGroup.Children.Add(new TranslateTransform(this.leftOffset, this.topOffset));            return transformGroup;        }        /// <summary>        /// 更新装饰器在装饰层中的位置.        /// </summary>        private void UpdatePosition()        {            ((AdornerLayer?)this.Parent)?.Update(this.AdornedElement);        }    }    /// <summary>    /// 专门用于拖拽视觉效果的装饰器类.    /// </summary>    private class DragAdorner : UIElementAdorner    {        /// <summary>        /// Gets 拖拽装饰容器.        /// </summary>        public DragDecorator Decorator => (DragDecorator)this.AdornVisual;        /// <summary>        /// Initializes a new instance of the <see cref="DragAdorner"/> class.        /// </summary>        /// <param name="dragVisual">拖拽显示的视觉内容.</param>        /// <param name="owner">所有者元素.</param>        public DragAdorner(object dragVisual, UIElement owner)            : base(new DragDecorator(), owner)        {            // 设置装饰器的内容.            this.Decorator.Content = dragVisual;        }    }    private bool adorderIsInVisualTree;    private AdornerLayer? layer;    private DragAdorner? adorner;    private DependencyObject? draggedElement;    /// <summary>    /// Gets or sets 拖拽相对于起始点的相对位置.    /// </summary>    public Point RelativeStartPoint { get; set; }    /// <summary>    /// Gets or sets 拖拽视觉效果的偏移量.    /// </summary>    public Point DragVisualOffset { get; set; }    /// <summary>    /// Gets or sets 拖拽提示的偏移量.    /// </summary>    public Point DragCueOffset { get; set; }    /// <summary>    /// Gets or sets 拖拽的内容.    /// </summary>    public object Content { get; set; }    /// <summary>    /// Gets 内部事件源（装饰层）.    /// </summary>    internal UIElement EventSource => this.layer!;    /// <summary>    /// 鼠标移动事件订阅.    /// </summary>    public event MouseEventHandler MouseMove    {        add { this.EventSource.PreviewMouseMove += value; }        remove { this.EventSource.PreviewMouseMove -= value; }    }    /// <summary>    /// 鼠标左键抬起事件订阅.    /// </summary>    public event MouseButtonEventHandler MouseLeftButtonUp    {        add { this.EventSource.MouseLeftButtonUp += value; }        remove { this.EventSource.MouseLeftButtonUp -= value; }    }    /// <summary>    /// 丢失鼠标捕获事件订阅.    /// </summary>    public event MouseEventHandler LostMouseCapture    {        add { this.EventSource.LostMouseCapture += value; }        remove { this.EventSource.LostMouseCapture -= value; }    }    /// <summary>    /// 获取焦点.    /// </summary>    /// <returns>是否成功.</returns>    public bool Focus()    {        return true;    }    /// <summary>    /// 释放鼠标捕获.    /// </summary>    public void ReleaseMouseCapture()    {        this.EventSource.ReleaseMouseCapture();    }    /// <summary>    /// 捕获鼠标.    /// </summary>    /// <returns>是否成功.</returns>    public bool CaptureMouse()    {        return this.EventSource.CaptureMouse();    }    /// <summary>    /// 移动拖拽装饰器到指定坐标.    /// </summary>    /// <param name="horizontalPos">绝对水平偏移.</param>    /// <param name="verticalPos">绝对垂直偏移.</param>    public void Move(double horizontalPos, double verticalPos)    {        // 如果装饰器尚未添加到视觉树，则执行添加操作.        if (!this.adorderIsInVisualTree)        {            this.adorderIsInVisualTree = true;            if (this.layer != null)            {                this.layer.Add(this.adorner);            }            if (this.adorner != null)            {                this.adorner.Decorator.LayoutUpdated += this.OnDecoratorLayoutUpdated;            }        }        if (this.adorner != null)        {            // 计算并设置相对于起始点的偏移.            this.adorner.LeftOffset = horizontalPos - this.RelativeStartPoint.X;            this.adorner.TopOffset = verticalPos - this.RelativeStartPoint.Y;        }    }    /// <summary>    /// 显示拖拽装饰器.    /// </summary>    /// <param name="dragSource">拖拽源元素.</param>    public void Show(DependencyObject dragSource)    {        ArgumentNullException.ThrowIfNull(dragSource, nameof(dragSource));        this.draggedElement = dragSource;        if (!(DragOperation.GetRootVisual(dragSource) is UIElement rootVisual))        {            throw new ArgumentException("DragSource should have UIElement as parent in the visual tree.");        }        // 获取对应的装饰层.        this.layer = AdornerLayer.GetAdornerLayer(rootVisual);        if (this.layer != null)        {            this.adorner = new DragAdorner(this.Content, rootVisual);            this.adorner.Decorator.RelativeStartPoint = this.RelativeStartPoint;            this.adorner.Decorator.DragVisualOffset = new Point(this.DragVisualOffset.X + this.DragCueOffset.X, this.DragVisualOffset.Y + this.DragCueOffset.Y);        }    }    /// <summary>    /// 隐藏并从装饰层移除装饰器.    /// </summary>    public void Hide()    {        if (this.adorner != null)        {            this.adorner.Decorator.ClearValue(DragDecorator.UseDefaultCursorsProperty);            this.adorner.Decorator.ClearValue(DragDecorator.EffectsProperty);        }        if (this.layer != null && this.adorner != null)        {            this.layer.Remove(this.adorner);        }    }    /// <summary>    /// 清理引用的资源.    /// </summary>    public void Clear()    {        this.layer = null;        this.adorner = null;    }    /// <summary>    /// 更新拖拽时的光标状态和视觉效果.    /// </summary>    /// <param name="dragDropEffects">拖拽效果.</param>    /// <param name="cursor">自定义光标.</param>    /// <param name="useDefaultCursors">a value indicating whether 是否使用默认光标.</param>    internal void UpdateCursorAndEffects(DragDropEffects dragDropEffects, Cursor cursor, bool useDefaultCursors)    {        if (this.adorner != null && (DragDropManager.IsDragInProgress || DragDropManager.IsInTouchDrag))        {            this.adorner.Decorator.UseDefaultCursors = useDefaultCursors;            if (useDefaultCursors)            {                // 隐藏标准鼠标光标，由装饰器处理视觉展现.                Mouse.OverrideCursor = Cursors.None;            }            else if (cursor != null)            {                Mouse.OverrideCursor = cursor;            }            else            {                Mouse.OverrideCursor = null;            }            this.adorner.Decorator.Effects = dragDropEffects;        }    }    /// <summary>    /// 当装饰器布局更新时的回调处理.    /// </summary>    private void OnDecoratorLayoutUpdated(object? sender, EventArgs e)    {        if (this.adorner == null)        {            return;        }        this.adorner.Decorator.LayoutUpdated -= this.OnDecoratorLayoutUpdated;        var cueArgs = new DragCuePositionEventArgs(DragDropManager.DragCuePositionEvent);        this.draggedElement?.RaiseEvent(cueArgs);        this.DragCueOffset = cueArgs.DragCueOffset;        this.adorner.Decorator.DragVisualOffset = new Point(this.DragVisualOffset.X + this.DragCueOffset.X, this.DragVisualOffset.Y + this.DragCueOffset.Y);        this.draggedElement = null;    }}